export function getSubjectsForGrade(grade) {
  return Object.keys(curriculum[grade]?.subjects || {});
}

export function getChaptersForSubject(grade, subject) {
  return (curriculum[grade]?.subjects?.[subject] || []).map(c => c.name);
}

export function getChapterInfo(grade, subject, chapterName) {
  const list = curriculum[grade]?.subjects?.[subject] || [];
  return list.find(c => c.name === chapterName) || null;
}

// Full ordered chapter list as a numbered outline — injected into prompts so the
// AI stays strictly within the selected class + subject syllabus.
export function getSyllabusOutline(grade, subject) {
  const list = curriculum[grade]?.subjects?.[subject] || [];
  return list.map((c, i) => i + 1 + '. ' + c.name + (c.unit ? ' — ' + c.unit : '')).join(String.fromCharCode(10));
}
